SELECT 
FROM ai_storage_configs

    del_flag = '0'
    AND site_id = #{siteId}
    AND name LIKE CONCAT('%', #{name}, '%')
    AND storage_type = #{storageType}
    AND status = #{status}

ORDER BY is_default DESC, id DESC

mapper.update:
UPDATE ai_storage_configs
site_id = #{siteId}, name = #{name}, code = #{code}, storage_type = #{storageType}, is_default = #{isDefault}, config_json = #{configJson}::jsonb, cdn_url = #{cdnUrl}, status = #{status}, update_by = #{updateBy}, update_time = NOW()
WHERE id = #{id}

UPDATE ai_storage_configs SET del_flag = '1', update_time = NOW()
WHERE id IN
#{id}
